def validate_portfolio(tickers, weights):
    """
    포트폴리오 입력값 검증
    """
    if len(tickers) != len(weights):
        raise ValueError("tickers와 weights의 길이가 다릅니다.")

    if not np.isclose(sum(weights), 1.0):
        raise ValueError(f"weights 합계가 1이 아닙니다. 현재 합계: {sum(weights)}")

    if any(w < 0 for w in weights):
        raise ValueError("weights에는 음수가 들어갈 수 없습니다.")


def download_adjusted_prices(tickers, start_date, end_date):
    """
    yfinance로 수정종가 다운로드.
    yfinance 버전에 따라 Adj Close가 없을 수 있어 auto_adjust=True 기반 Close도 처리.
    """
    data = yf.download(
        tickers,
        start=start_date,
        end=end_date,
        auto_adjust=False,
        progress=False
    )

    if data.empty:
        raise ValueError("가격 데이터를 가져오지 못했습니다. 티커를 확인하세요.")

    # 여러 티커일 때
    if isinstance(data.columns, pd.MultiIndex):
        if "Adj Close" in data.columns.get_level_values(0):
            prices = data["Adj Close"].copy()
        else:
            prices = data["Close"].copy()
    else:
        # 티커가 하나일 때
        if "Adj Close" in data.columns:
            prices = data[["Adj Close"]].copy()
            prices.columns = tickers
        else:
            prices = data[["Close"]].copy()
            prices.columns = tickers

    prices = prices.dropna(how="all")
    prices = prices.ffill().dropna()

    # 혹시 단일 티커 Series가 되면 DataFrame으로 변환
    if isinstance(prices, pd.Series):
        prices = prices.to_frame(name=tickers[0])

    return prices


def calculate_daily_returns(prices):
    """
    일별 수익률 계산
    """
    returns = prices.pct_change().dropna()
    return returns


def calculate_portfolio_returns(asset_returns, weights):
    """
    자산별 일별수익률과 비중을 이용해 포트폴리오 일별수익률 계산
    """
    weights_array = np.array(weights)
    portfolio_returns = asset_returns.dot(weights_array)
    portfolio_returns.name = "portfolio_return"
    return portfolio_returns


def calculate_cumulative_value(portfolio_returns, initial_amount=100):
    """
    누적 포트폴리오 가치 계산
    """
    cumulative_value = initial_amount * (1 + portfolio_returns).cumprod()
    cumulative_value.name = "portfolio_value"
    return cumulative_value


def calculate_mdd(cumulative_value):
    """
    MDD 계산.
    누적가치 기준 최고점 대비 하락률 중 최저값.
    """
    running_max = cumulative_value.cummax()
    drawdown = cumulative_value / running_max - 1
    mdd = drawdown.min()
    return mdd, drawdown


def calculate_sortino_ratio(portfolio_returns, risk_free_rate=0.035):
    """
    소르티노 비율 계산.
    하방 변동성만 위험으로 반영.
    """
    annual_return = portfolio_returns.mean() * TRADING_DAYS
    daily_risk_free = risk_free_rate / TRADING_DAYS

    downside_returns = portfolio_returns[portfolio_returns < daily_risk_free] - daily_risk_free
    downside_deviation = np.sqrt((downside_returns ** 2).mean()) * np.sqrt(TRADING_DAYS)

    if downside_deviation == 0 or np.isnan(downside_deviation):
        return np.nan

    sortino = (annual_return - risk_free_rate) / downside_deviation
    return sortino


def calculate_after_tax_return(nominal_return, tax_config):
    """
    단순 세후수익률 계산.

    현재 버전은 MVP용 단순 계산:
    세후수익률 = 명목수익률 - 세금비용 - 거래수수료 - 환전비용

    실제 세법 전체를 반영한 것이 아니라,
    대시보드 시연용으로 비용 차감 구조를 보여주는 목적.
    """
    dividend_tax_rate = tax_config.get("dividend_tax_rate", 0.154)
    capital_gains_tax_rate = tax_config.get("capital_gains_tax_rate", 0.22)
    trading_fee_rate = tax_config.get("trading_fee_rate", 0.001)
    fx_fee_rate = tax_config.get("fx_fee_rate", 0.002)
    annual_turnover = tax_config.get("annual_turnover", 1.0)

    # 단순 가정: 전체 수익 중 30%는 배당/이자 성격, 70%는 자본차익 성격
    income_return = nominal_return * 0.3
    capital_gain_return = nominal_return * 0.7

    income_tax_cost = max(income_return, 0) * dividend_tax_rate
    capital_gains_tax_cost = max(capital_gain_return, 0) * capital_gains_tax_rate

    trading_cost = trading_fee_rate * annual_turnover
    fx_cost = fx_fee_rate * annual_turnover

    after_tax_return = nominal_return - income_tax_cost - capital_gains_tax_cost - trading_cost - fx_cost

    tax_detail = {
        "nominal_return": nominal_return,
        "income_tax_cost": income_tax_cost,
        "capital_gains_tax_cost": capital_gains_tax_cost,
        "trading_cost": trading_cost,
        "fx_cost": fx_cost,
        "after_tax_return": after_tax_return
    }

    return after_tax_return, tax_detail


def calculate_metrics(portfolio_returns, cumulative_value, risk_free_rate=0.035, tax_config=None):
    """
    6종 지표 계산:
    기대수익률, 변동성, 샤프지수, MDD, 세후수익률, 소르티노 비율
    """
    annual_return = portfolio_returns.mean() * TRADING_DAYS
    annual_volatility = portfolio_returns.std() * np.sqrt(TRADING_DAYS)

    if annual_volatility == 0 or np.isnan(annual_volatility):
        sharpe_ratio = np.nan
    else:
        sharpe_ratio = (annual_return - risk_free_rate) / annual_volatility

    mdd, drawdown = calculate_mdd(cumulative_value)
    sortino_ratio = calculate_sortino_ratio(portfolio_returns, risk_free_rate)

    if tax_config is None:
        after_tax_return = np.nan
        tax_detail = {}
    else:
        after_tax_return, tax_detail = calculate_after_tax_return(annual_return, tax_config)

    metrics = {
        "expected_return": annual_return,
        "volatility": annual_volatility,
        "sharpe_ratio": sharpe_ratio,
        "mdd": mdd,
        "after_tax_return": after_tax_return,
        "sortino_ratio": sortino_ratio
    }

    return metrics, drawdown, tax_detail


def make_allocation_chart_data(tickers, weights, asset_classes=None):
    """
    도넛/파이 차트용 데이터 생성
    """
    chart_data = []
    for ticker, weight in zip(tickers, weights):
        chart_data.append({
            "ticker": ticker,
            "asset_class": asset_classes.get(ticker, "기타") if asset_classes else "기타",
            "weight": weight,
            "weight_percent": weight * 100
        })
    return chart_data


def make_backtest_chart_data(cumulative_value):
    """
    프론트엔드 라인 차트용 데이터 생성
    """
    df = cumulative_value.reset_index()
    df.columns = ["date", "portfolio_value"]
    df["date"] = df["date"].dt.strftime("%Y-%m-%d")
    return df.to_dict(orient="records")


def make_drawdown_chart_data(drawdown):
    """
    MDD/낙폭 차트용 데이터 생성
    """
    df = drawdown.reset_index()
    df.columns = ["date", "drawdown"]
    df["date"] = df["date"].dt.strftime("%Y-%m-%d")
    df["drawdown_percent"] = df["drawdown"] * 100
    return df.to_dict(orient="records")


def make_correlation_heatmap_data(asset_returns):
    """
    상관관계 히트맵용 데이터 생성
    """
    corr = asset_returns.corr()

    heatmap_data = []
    for row_asset in corr.index:
        for col_asset in corr.columns:
            heatmap_data.append({
                "asset_x": row_asset,
                "asset_y": col_asset,
                "correlation": corr.loc[row_asset, col_asset]
            })

    return corr, heatmap_data


def run_single_portfolio_analysis(
    portfolio_name,
    portfolio_config,
    start_date,
    end_date,
    initial_amount=100,
    risk_free_rate=0.035,
    tax_config=None
):
    """
    단일 포트폴리오 전체 분석 실행
    """
    tickers = portfolio_config["tickers"]
    weights = portfolio_config["weights"]
    asset_classes = portfolio_config.get("asset_classes", {})

    validate_portfolio(tickers, weights)

    prices = download_adjusted_prices(tickers, start_date, end_date)
    prices = prices[tickers]  # 입력 순서 유지

    asset_returns = calculate_daily_returns(prices)
    portfolio_returns = calculate_portfolio_returns(asset_returns, weights)
    cumulative_value = calculate_cumulative_value(portfolio_returns, initial_amount)

    metrics, drawdown, tax_detail = calculate_metrics(
        portfolio_returns,
        cumulative_value,
        risk_free_rate=risk_free_rate,
        tax_config=tax_config
    )

    corr_matrix, corr_heatmap_data = make_correlation_heatmap_data(asset_returns)

    result = {
        "portfolio_name": portfolio_name,
        "tickers": tickers,
        "weights": weights,
        "metrics": metrics,
        "tax_detail": tax_detail,
        "allocation_chart": make_allocation_chart_data(tickers, weights, asset_classes),
        "backtest_chart": make_backtest_chart_data(cumulative_value),
        "drawdown_chart": make_drawdown_chart_data(drawdown),
        "correlation_heatmap": corr_heatmap_data,
        "raw": {
            "prices": prices,
            "asset_returns": asset_returns,
            "portfolio_returns": portfolio_returns,
            "cumulative_value": cumulative_value,
            "drawdown": drawdown,
            "correlation_matrix": corr_matrix
        }
    }

    return result

