def run_stress_test(portfolio_config, stress_scenarios, initial_amount):
    tickers = portfolio_config["tickers"]
    weights = portfolio_config["weights"]
    asset_classes = portfolio_config.get("asset_classes", {})

    scenario_results = []

    for scenario_name, shock_map in stress_scenarios.items():
        portfolio_shock = 0

        asset_impacts = []
        for ticker, weight in zip(tickers, weights):
            asset_class = asset_classes.get(ticker, "기타")
            shock = shock_map.get(asset_class, 0)
            weighted_impact = weight * shock
            portfolio_shock += weighted_impact

            asset_impacts.append({
                "ticker": ticker,
                "asset_class": asset_class,
                "weight": weight,
                "shock": shock,
                "weighted_impact": weighted_impact
            })

        scenario_results.append({
            "scenario": scenario_name,
            "portfolio_return_impact": portfolio_shock,
            "estimated_pnl": initial_amount * portfolio_shock,
            "estimated_value_after_shock": initial_amount * (1 + portfolio_shock),
            "asset_impacts": asset_impacts
        })

    return scenario_results


